import { useState, useEffect } from "react";
import Sidebar from "./Sidebar";
import Topbar from "./Topbar";

export default function ClientManagement() {

  const [showForm, setShowForm] = useState(false);
  const [clients, setClients] = useState([]);
  const [projects, setProjects] = useState([]);
  const [search, setSearch] = useState("");
  const [editId, setEditId] = useState(null);

  const [formData, setFormData] = useState({
    name: "",
    co_owner: "",
    phone: "",
    address: "",
    project: "",
    floor: "",
    room: "",
    amount_paid: "",
    payment_mode: "",
    bank_name: "",
    cheque_no: "",
    installments: []
  });

  // ================= FETCH CLIENTS =================
  const fetchClients = async () => {
    try {
      const res = await fetch("http://localhost:5000/api/clients");
      const data = await res.json();

      setClients(Array.isArray(data) ? data : data.clients || data.data || []);
    } catch (err) {
      console.log(err);
    }
  };

  // ================= FETCH PROJECTS =================
  const fetchProjects = async () => {
    try {
      const res = await fetch("http://localhost:5000/api/projects");
      const data = await res.json();

      setProjects(Array.isArray(data) ? data : data.projects || data.data || []);
    } catch (err) {
      console.log(err);
    }
  };

  useEffect(() => {
    fetchClients();
    fetchProjects();
  }, []);

  // ================= PROJECT =================
  const selectedProject = projects.find(
    p => p.name === formData.project
  );

  const generateRooms = (floor) => {
    if (!floor || !selectedProject) return [];

    let rooms = [];
    const totalRooms = selectedProject.roomsPerFloor || 10;

    for (let i = 1; i <= totalRooms; i++) {
      rooms.push(`${floor}${i.toString().padStart(2, "0")}`);
    }
    return rooms;
  };

  // ================= INPUT =================
  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData({ ...formData, [name]: value });
  };

  // ================= INSTALLMENTS =================
  const addInstallment = () => {
    setFormData({
      ...formData,
      installments: [...formData.installments, { amount: "", date: "" }]
    });
  };

  // ================= SUBMIT (FIXED) =================
  const handleSubmit = async () => {
    try {

      if (editId) {
        await fetch(`http://localhost:5000/api/clients/${editId}`, {
          method: "PUT",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify(formData)
        });
      } else {
        await fetch("http://localhost:5000/api/clients", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify(formData)
        });
      }

      // 🔥 IMPORTANT FIX: ALWAYS REFRESH AFTER SAVE
      const res = await fetch("http://localhost:5000/api/clients");
      const data = await res.json();

      setClients(Array.isArray(data) ? data : data.clients || data.data || []);

      setShowForm(false);
      setEditId(null);

      setFormData({
        name: "",
        co_owner: "",
        phone: "",
        address: "",
        project: "",
        floor: "",
        room: "",
        amount_paid: "",
        payment_mode: "",
        bank_name: "",
        cheque_no: "",
        installments: []
      });

    } catch (err) {
      console.log(err);
    }
  };

  // ================= SEARCH =================
  const filteredClients = clients.filter(c =>
    c.name?.toLowerCase().includes(search.toLowerCase()) ||
    c.project?.toLowerCase().includes(search.toLowerCase())
  );

  return (
    <div className="flex bg-gray-100 min-h-screen">

      <Sidebar />

      <div className="flex-1 flex flex-col">

        <Topbar />

        <div className="p-8">

          {/* HEADER */}
          <div className="flex justify-between mb-6">
            <h1 className="text-3xl font-semibold">
              Client & Booking Details
            </h1>

            <button
              onClick={() => setShowForm(true)}
              className="bg-orange-500 text-white px-6 py-3 rounded-xl"
            >
              + Add Client
            </button>
          </div>

          {/* SEARCH */}
          <input
            type="text"
            placeholder="Search by name or project..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="border px-4 py-3 rounded-xl w-full mb-6"
          />

          {/* CLIENT LIST */}
          <div className="bg-white rounded-xl shadow p-4">
            <h2 className="text-xl font-semibold mb-4">Clients</h2>

            {filteredClients.length === 0 ? (
              <p>No clients found</p>
            ) : (
              filteredClients.map((client, i) => (
                <div
                  key={client.id || i}
                  className="border-b py-3 flex justify-between"
                >
                  <div>
                    <p className="font-semibold">{client.name}</p>
                    <p className="text-sm text-gray-600">
                      {client.project} | Floor: {client.floor} | Room: {client.room}
                    </p>
                  </div>

                  <div>
                    ₹ {client.amount_paid}
                  </div>
                </div>
              ))
            )}
          </div>

          {/* FORM */}
          {showForm && (
            <div className="bg-white p-6 rounded-xl shadow mt-6">

              <h2 className="text-xl font-semibold mb-4">
                Add Client
              </h2>

              <input
                name="name"
                placeholder="Name"
                value={formData.name}
                onChange={handleChange}
                className="border p-2 w-full mb-2"
              />

              <input
                name="phone"
                placeholder="Phone"
                value={formData.phone}
                onChange={handleChange}
                className="border p-2 w-full mb-2"
              />

              <select
                name="project"
                value={formData.project}
                onChange={handleChange}
                className="border p-2 w-full mb-2"
              >
                <option value="">Select Project</option>
                {projects.map(p => (
                  <option key={p.id} value={p.name}>
                    {p.name}
                  </option>
                ))}
              </select>

              <div className="flex gap-3 mt-4">

                <button
                  onClick={handleSubmit}
                  className="bg-orange-500 text-white px-4 py-2 rounded"
                >
                  Save
                </button>

                <button
                  onClick={() => setShowForm(false)}
                  className="bg-gray-300 px-4 py-2 rounded"
                >
                  Cancel
                </button>

              </div>

            </div>
          )}

        </div>

      </div>

    </div>
  );
}
